13073                        unsigned ReduxWidth, const TargetTransformInfo *TTI) {
13074     assert(VectorizedValue && "Need to have a vectorized tree node");
13075     assert(isPowerOf2_32(ReduxWidth) &&
13076            "We only handle power-of-two reductions for now");
13077     assert(RdxKind != RecurKind::FMulAdd &&
13078            "A call to the llvm.fmuladd intrinsic is not handled yet");
