13084   /// Emits optimized code for unique scalar value reused \p Cnt times.
13085   Value *emitScaleForReusedOps(Value *VectorizedValue, IRBuilderBase &Builder,
13086                                unsigned Cnt) {
13087     assert(IsSupportedHorRdxIdentityOp &&
13088            "The optimization of matched scalar identity horizontal reductions "
13089            "must be supported.");
13090     switch (RdxKind) {
13091     case RecurKind::Add: {
13092       // res = mul vv, n
13093       Value *Scale = ConstantInt::get(VectorizedValue->getType(), Cnt);
13094       LLVM_DEBUG(dbgs() << "SLP: Add (to-mul) " << Cnt << "of "
13095                         << VectorizedValue << ". (HorRdx)\n");
13096       return Builder.CreateMul(VectorizedValue, Scale);
13097     }
13098     case RecurKind::Xor: {
13099       // res = n % 2 ? 0 : vv
13100       LLVM_DEBUG(dbgs() << "SLP: Xor " << Cnt << "of " << VectorizedValue
13101                         << ". (HorRdx)\n");
13102       if (Cnt % 2 == 0)
13103         return Constant::getNullValue(VectorizedValue->getType());
13104       return VectorizedValue;
13105     }
13106     case RecurKind::FAdd: {
13107       // res = fmul v, n
13108       Value *Scale = ConstantFP::get(VectorizedValue->getType(), Cnt);
13109       LLVM_DEBUG(dbgs() << "SLP: FAdd (to-fmul) " << Cnt << "of "
13110                         << VectorizedValue << ". (HorRdx)\n");
13111       return Builder.CreateFMul(VectorizedValue, Scale);
13112     }
13113     case RecurKind::And:
13114     case RecurKind::Or:
13115     case RecurKind::SMax:
13116     case RecurKind::SMin:
13117     case RecurKind::UMax:
13118     case RecurKind::UMin:
13119     case RecurKind::FMax:
13120     case RecurKind::FMin:
13121       // res = vv
13122       return VectorizedValue;
13123     case RecurKind::Mul:
13124     case RecurKind::FMul:
13125     case RecurKind::FMulAdd:
13126     case RecurKind::SelectICmp:
13127     case RecurKind::SelectFCmp:
13128     case RecurKind::None:
13129       llvm_unreachable("Unexpected reduction kind for repeated scalar.");
13130     }
13131     return nullptr;
13132   }
