13317 /// Try and get a reduction value from a phi node.
13318 ///
13319 /// Given a phi node \p P in a block \p ParentBB, consider possible reductions
13320 /// if they come from either \p ParentBB or a containing loop latch.
13321 ///
13322 /// \returns A candidate reduction value if possible, or \code nullptr \endcode
13323 /// if not possible.
13324 static Value *getReductionValue(const DominatorTree *DT, PHINode *P,
13325                                 BasicBlock *ParentBB, LoopInfo *LI) {
13326   // There are situations where the reduction value is not dominated by the
13327   // reduction phi. Vectorizing such cases has been reported to cause
13328   // miscompiles. See PR25787.
13329   auto DominatedReduxValue = [&](Value *R) {
13330     return isa<Instruction>(R) &&
13331            DT->dominates(P->getParent(), cast<Instruction>(R)->getParent());
13332   };
13333 
13334   Value *Rdx = nullptr;
13335 
13336   // Return the incoming value if it comes from the same BB as the phi node.
13337   if (P->getIncomingBlock(0) == ParentBB) {
13338     Rdx = P->getIncomingValue(0);
13339   } else if (P->getIncomingBlock(1) == ParentBB) {
13340     Rdx = P->getIncomingValue(1);
13341   }
13342 
13343   if (Rdx && DominatedReduxValue(Rdx))
13344     return Rdx;
13345 
13346   // Otherwise, check whether we have a loop latch to look at.
13347   Loop *BBL = LI->getLoopFor(ParentBB);
13348   if (!BBL)
13349     return nullptr;
13350   BasicBlock *BBLatch = BBL->getLoopLatch();
13351   if (!BBLatch)
13352     return nullptr;
13353 
13354   // There is a loop latch, return the incoming value if it comes from
13355   // that. This reduction pattern occasionally turns up.
13356   if (P->getIncomingBlock(0) == BBLatch) {
13357     Rdx = P->getIncomingValue(0);
13358   } else if (P->getIncomingBlock(1) == BBLatch) {
13359     Rdx = P->getIncomingValue(1);
13360   }
13361 
13362   if (Rdx && DominatedReduxValue(Rdx))
13363     return Rdx;
13364 
13365   return nullptr;
13366 }
